import{_ as n}from"./plugin-vue_export-helper-c27b6911.js";import{r as e,o,c as g,a as s,b as r,e as i,d as a}from"./app-45b6ee47.js";const d="/assets/wpsMOQK0A-20230617203947-h3vaoij-00256cbb.png",h="/assets/net-img-ev4LxQ-20230730162750-oef5cg2-05f21555.png",p="/assets/net-img-0PdsOw-20230730162751-4g9993x-215d20b2.png",c="/assets/net-img-pGGTAT-20230730162751-zy67unu-fd704f05.png",l="/assets/net-img-QMGkn2-20230730162751-fhbat49-f15f36e7.png",m="/assets/net-img-joccTd-20230730162751-3b9p6jn-8e175636.png",f="/assets/net-img-DfvMkD-20230730162751-hsxtsb8-3bcf7b50.jpg",u={},b=a('<h2 id="什么是redis​-​" tabindex="-1"><a class="header-anchor" href="#什么是redis​-​" aria-hidden="true">#</a> 什么是Redis​？​</h2><p><em><strong>Redis</strong></em>是一个使用C语言编写的开源、高性能的<strong>非关系型的键值对数据库</strong></p><p><em><strong>Redis</strong></em>可以存储键和五种不同类型值之间的映射，键的类型只能为字符串</p><p>值支持<strong>五种数据类型</strong>：<strong>字符串</strong>、<strong>列表</strong>、<strong>集合</strong>、<strong>散列表</strong>、<strong>有序集合</strong></p><p>与传统数据库不同的是<em><strong>Redis</strong></em>的数据是存在内存中的，所以读写速度非常快</p><p>因此<em><strong>Redis</strong></em>被广泛<strong>应用于缓存方向</strong></p><p><em><strong>Redis</strong></em>每秒可以处理<strong>超过10万次</strong>读写操作，是已知性能最快的<strong>关系型的键值对数据库</strong></p><p><em><strong>Redis</strong></em>也经常用来做<strong>分布式锁</strong>，完成一些秒杀等有关的业务，提高服务的<strong>整体并发抗压能力</strong></p><p><em><strong>Redis</strong></em>也支持<strong>事务</strong>、<strong>持久化</strong>、多种集群方案，也同样支持类似<strong>MySQL数据库</strong>的<strong>主从备份</strong></p><blockquote><p>BSD是&quot;Berkeley Software Distribution&quot;的缩写，意思是“伯克利软件发型版本”。<br> BSD开源协议是一个给予使用者很大自由的协议。可以自由的使用，修改源代码，也可以将修改后的代码作为开源或者专有软件在发布。<br> BSD代码鼓励代码共享，但需要尊重代码作者的著作权。<br> BSD由于允许使用者修改和重新发布代码，也允许使用或在BSD代码上开发商业软件发布和销售，一次是对商业集成很友好的协议。</p></blockquote><h2 id="简述redis的优点" tabindex="-1"><a class="header-anchor" href="#简述redis的优点" aria-hidden="true">#</a> <strong>简述Redis的优点？</strong></h2><ul><li>读写<strong>性能优异</strong>：<em><strong>Redis</strong></em>读的速度是<strong>110000次/s</strong>，写的速度是<strong>81000次/s</strong></li><li>支持<strong>数据持久化</strong>：支持<em><strong>AOF</strong></em>和<em><strong>RDB</strong></em>两种持久化方式，有效保证数据不丢失</li><li>支持<strong>事务</strong>：<em><strong>Redis</strong></em>的所有操作都是<strong>原子性</strong>，同时<em><strong>Redis</strong></em>还支持对几个<strong>操作合并</strong>后的<strong>原子性</strong></li><li>数据<strong>类型丰富</strong>：五大数据类型任您选择，<strong>string</strong>、<strong>list</strong>、<strong>set</strong>、<strong>zset</strong>、<strong>hash</strong></li><li>支持<strong>主从复制</strong>：主机会自动将数据同步到从机，还可以进行读写分离</li><li>丰富<strong>特性</strong>：<em><strong>Redis</strong></em>还支持<strong>发布者订阅者模式</strong>，<strong>键空间事件</strong>，<strong>过期键消息通知</strong>等功能</li></ul><h2 id="简述redis的缺点" tabindex="-1"><a class="header-anchor" href="#简述redis的缺点" aria-hidden="true">#</a> <strong>简述Redis的缺点？</strong></h2><ul><li>作为<strong>缓存</strong>时，经常存在与<strong>数据库数据</strong>不一致的问题</li><li>缓存的<strong>雪崩问题</strong></li><li>缓存也能出现<strong>击穿问题</strong></li><li>缓存的<strong>并发竞争</strong>问题</li></ul><h2 id="redis介绍相关知识" tabindex="-1"><a class="header-anchor" href="#redis介绍相关知识" aria-hidden="true">#</a> Redis介绍相关知识</h2><p>Redis是单线程+多路IO复用技术</p><p>多路复用是指使用一个线程来检查多个文件描述符（Socket）的就绪状态，比如调用select和poll函数，传入多个文件描述符，如果有一个文件描述符就绪，则返回，否则阻塞直到超时。得到就绪状态后进行真正的操作可以在同一个线程里执行，也可以启动线程执行（比如使用线程池）</p><p>串行 vs 多线程+锁（memcached） vs 单线程+多路IO复用(Redis)</p><p>（与Memcache三点不同: 支持多数据类型，支持持久化，单线程+多路IO复用）</p><p>​<img src="'+d+'" alt="img" loading="lazy">​</p><h2 id="单线程的redis为什么这么快" tabindex="-1"><a class="header-anchor" href="#单线程的redis为什么这么快" aria-hidden="true">#</a> 单线程的Redis为什么这么快？</h2><blockquote><p>单进程</p></blockquote><p>Redis使用了单线程架构和I/O多路复用模型来实现高性能的内存数据库服务。</p><blockquote><p>单线程还能这么快</p></blockquote><p>第一，纯内存访问，Redis将所有数据放在内存中，内存的响应时长大约为100纳秒，这是Redis达到每秒万级别访问的重要基础。</p><p>第二，非阻塞I/O，Redis使用epoll作为I/O多路复用技术的实现，再加上Redis自身的事件处理模型将epoll中的连接、读写、关闭都转换为事件，不在网络I/O上浪费过多的时间。</p><p>第三，单线程避免了线程切换和竞态产生的消耗。</p><p>但是单线程会有一个问题：对于每个命令的执行时间是有要求的。如果 某个命令执行过长，会造成其他命令的阻塞，对于Redis这种高性能的服务 来说是致命的，所以Redis是面向快速执行场景的数据库。</p><h2 id="redis有哪些适合的场景" tabindex="-1"><a class="header-anchor" href="#redis有哪些适合的场景" aria-hidden="true">#</a> <strong>Redis有哪些适合的场景？</strong></h2><h3 id="热点数据的缓存" tabindex="-1"><a class="header-anchor" href="#热点数据的缓存" aria-hidden="true">#</a> <strong>热点数据的缓存</strong></h3><p>由于<em><strong>Redis</strong></em>访问速度块、<strong>支持的数据类型丰富</strong>，所以<em><strong>Redis</strong></em>很适合用来存储<strong>热点数据</strong></p><p>另外结合<em><strong>expire</strong></em>，我们可以设置过期时间然后再进行缓存更新操作</p><p>这个功能最为常见，我们几乎所有的项目都有所运用</p><h3 id="限时业务的运用" tabindex="-1"><a class="header-anchor" href="#限时业务的运用" aria-hidden="true">#</a> <strong>限时业务的运用</strong></h3><p><em><strong>Redis</strong></em>中可以使用<em><strong>expire</strong></em>命令设置一个键的生存时间，到时间后<em><strong>Redis</strong></em>会删除它</p><p>利用这一特性可以运用在<strong>限时</strong>的<strong>优惠活动信息</strong>、<strong>手机验证码</strong>等业务场景</p><p>还可以结合<strong>键空间事件</strong>捕捉<strong>过期事件</strong>，做一些更为人性化的功能，比如<strong>过期自动提醒</strong></p><h3 id="计数器相关问题" tabindex="-1"><a class="header-anchor" href="#计数器相关问题" aria-hidden="true">#</a> <strong>计数器相关问题</strong></h3><p><em><strong>Redis</strong></em>由于<em><strong>incrby</strong></em>命令可以实现<strong>原子性的递增</strong>，所以可以运用于<strong>高并发</strong>的<strong>秒杀活动</strong>、<strong>分布式序列号</strong>的生成等<strong>大规模访问</strong>的功能中</p><p>具体业务还体现在比如限制<strong>一个手机号发多少条短信</strong></p><p>一个接口一分钟限制多少请求，一个接口一天限制调用多少次等等</p><h3 id="排行榜相关问题" tabindex="-1"><a class="header-anchor" href="#排行榜相关问题" aria-hidden="true">#</a> <strong>排行榜相关问题</strong></h3><p>使用<em><strong>Redis</strong></em>的<em><strong>zset</strong></em>直接进行有序数据的内存维护，不光可以维护排行榜的先后顺序</p><p>还可以提高访问速度</p><h3 id="分布式锁" tabindex="-1"><a class="header-anchor" href="#分布式锁" aria-hidden="true">#</a> <strong>分布式锁</strong></h3><p>这个主要利用<em><strong>Redis</strong></em>的<em><strong>setnx</strong></em>命令进行，并<strong>搭配一个过期时间</strong>防止某一个客户端宕机导致<strong>死锁</strong></p><p>分布式锁也常用在秒杀过程中的购买流程</p><p>支付环节<strong>首先加锁</strong>，之后<strong>判断库存</strong>数量是否满足购买条件，<strong>购买成功</strong>，<strong>减去库存</strong>，释放锁，交给另外一个客户端进行持锁购买</p><h3 id="延时操作" tabindex="-1"><a class="header-anchor" href="#延时操作" aria-hidden="true">#</a> <strong>延时操作</strong></h3><p>该功能主要通过<strong>键空间事件</strong>来搞定</p><p>比如某些情况用户<strong>购买过程未支付</strong>，但是却会占据一个<strong>实际的库存个数</strong>，那么可以通过使用<strong>键空间事件</strong>，存储当前<strong>购买订单id</strong>，设置一个<strong>过期时间</strong>，监听到这个<em><strong>key</strong></em>的<strong>过期键空间</strong>，通过<strong>键空间事件</strong>的触发来进行用户购买的提示，或者<strong>直接删除</strong>正在支付的过期订单，将库存量还原</p><h3 id="消息队列" tabindex="-1"><a class="header-anchor" href="#消息队列" aria-hidden="true">#</a> <strong>消息队列</strong></h3><p><em><strong>Redis</strong></em>也可以实现消息队列的功能，比如结合一些类似<em><strong>celery</strong></em>的<strong>异步框架</strong>完成异步任务的处理</p><h2 id="redis操作" tabindex="-1"><a class="header-anchor" href="#redis操作" aria-hidden="true">#</a> Redis操作</h2><p>简单对redis 命令进行总结、归纳。</p><h3 id="键" tabindex="-1"><a class="header-anchor" href="#键" aria-hidden="true">#</a> 键</h3><figure><img src="'+h+'" alt="ev4LxQ" tabindex="0" loading="lazy"><figcaption>ev4LxQ</figcaption></figure><h3 id="string" tabindex="-1"><a class="header-anchor" href="#string" aria-hidden="true">#</a> String</h3><figure><img src="'+p+'" alt="0PdsOw" tabindex="0" loading="lazy"><figcaption>0PdsOw</figcaption></figure><h3 id="list" tabindex="-1"><a class="header-anchor" href="#list" aria-hidden="true">#</a> List</h3><figure><img src="'+c+'" alt="pGGTAT" tabindex="0" loading="lazy"><figcaption>pGGTAT</figcaption></figure><h3 id="hash" tabindex="-1"><a class="header-anchor" href="#hash" aria-hidden="true">#</a> Hash</h3><figure><img src="'+l+'" alt="QMGkn2" tabindex="0" loading="lazy"><figcaption>QMGkn2</figcaption></figure><h3 id="set" tabindex="-1"><a class="header-anchor" href="#set" aria-hidden="true">#</a> Set</h3><figure><img src="'+m+'" alt="joccTd" tabindex="0" loading="lazy"><figcaption>joccTd</figcaption></figure><h3 id="zset" tabindex="-1"><a class="header-anchor" href="#zset" aria-hidden="true">#</a> Zset</h3><figure><img src="'+f+'" alt="DfvMkD" tabindex="0" loading="lazy"><figcaption>DfvMkD</figcaption></figure>',67),x={href:"https://redis.com.cn/documentation.html",target:"_blank",rel:"noopener noreferrer"},R=s("p",null,"‍",-1);function _(k,y){const t=e("ExternalLinkIcon");return o(),g("div",null,[b,s("p",null,[r("更多命令参考"),s("a",x,[r("Redis中文教程"),i(t)])]),R])}const z=n(u,[["render",_],["__file","index.html.vue"]]);export{z as default};
